// Liga de Tenis Sohail — app.js
// Las claves vienen de config.js (cargado antes en index.html)

const LAYOUT='selector';const LOGINMODE='groups';
const PUNTOS={1:[35,34,33,32,31],2:[32,31,30,29,28],3:[29,28,27,26,25],4:[26,25,24,23,22],5:[23,22,21,20,19],6:[20,19,18,17,16],7:[17,16,15,14,13],8:[14,13,12,11,10],9:[14,13,12,11,10],10:[11,10,9,8,7],11:[8,7,6,5,4],12:[5,4,3,2,1]};
let DESTINO={1:['G1','G1','G2','G2','G3'],2:['G1','G1','G2','G3','G4'],3:['G1','G2','G3','G4','G5'],4:['G2','G3','G4','G5','G6'],5:['G3','G4','G5','G6','G7'],6:['G4','G5','G6','G7','G8'],7:['G5','G6','G7','G8','G9'],8:['G6','G7','G8','G9','G10'],9:['G7','G8','G9','G10','G11'],10:['G8','G9','G10','G11','G12'],11:['G9','G10','G11','G12','G12'],12:['G10','G11','G11','G12','G12']};
function ptsForPos(gid,pos){const pb=PUNTOS[gid];if(!pb)return 0;return pos<pb.length?pb[pos]:Math.max(0,pb[pb.length-1]-(pos-pb.length+1));}
let FECHAS=['15/06/26 – 19/07/26','20/07/26 – 23/08/26','24/08/26 – 27/09/26'];
const C1=[['Neil Young','Marcos Gavassa','Jeremy Pérez','Leo Ramos','Adrián Mariscal'],['Manuel de la Coba','Javier Lopez','Miguel Ángel Vargas','Jaime Govantes','Luis Gil-Delgado'],['Javier Ariño','Germán Pacheco','Oscar Pacheco','Dumitru Bucse','Gustavo Rodriguez'],['Juan Antonio Tabernero','Carlos Marin','Jose Maria Cantero','Javier Urbieta','Marco Musso'],['Miguel Ángel Acevedo','Esteban Benítez','Cesar Henry','Borja Muñoz','Julio Pajares'],['Borja Rosales','Rustam Abduraufov','Alfredo Perez Playa','Alberto Álvarez','Jose Manuel Maese'],['Jaime Crespi','Ildefonso Delgado','Viktor Kachalin','Álvaro Jaime','Ángel Poyato'],['Jesús Bermúdez','David González','Istvan Simon','Nicolás Feller','Enrique Urdiales'],['Juan Ignacio Insausti','Rafael Alves','Miguel Ángel Mérida','David Ruiz','Alejandro Gil'],['Emanuele Procopio','Andrés Slako','Anita Rachwalska','Maria Fernanda Quinto','Raúl Rubio'],['Carolina Graciano','Lucca Maciel','José Alejandro López','Tim Dobbin','Pedro Gómez'],['Paola Mateo','Maurizio Rainieri','Borja Martín','Julio Corzo','Manuel Soriano']];
let cycles=[{n:1,status:'active',groups:C1.map(p=>({players:[...p]}))},{n:2,status:'locked',groups:null},{n:3,status:'locked',groups:null}];
let playoff={started:false,numTramos:4,tramos:[],results:{},viewT:0,qualified:[]};
let matches=[],matchId=1,activeN=1,viewCycle=1,subView='grupos',currentModal=null,formClub='',poContext=null,selGroup=1,adminMode='';
let ALLNAMES=C1.flat();
function ensureDestino(gid,len){if(!DESTINO[gid])DESTINO[gid]=[];while(DESTINO[gid].length<len)DESTINO[gid].push('G'+Math.min(gid+1,12));return DESTINO[gid];}
function addPlayerToCycle(name,gid){if(!name||!cycles[activeN-1].groups[gid-1])return false;if(ALLNAMES.indexOf(name)<0)ALLNAMES.push(name);if(!USERS[name])USERS[name]={role:'player',pass:'tenis',name};cycles[activeN-1].groups[gid-1].players.push(name);ensureDestino(gid,cycles[activeN-1].groups[gid-1].players.length);return true;}
function buildUsers(){const u={admin:{role:'admin',pass:'admin123',name:'Organización',email:'',tel:''}};ALLNAMES.forEach(n=>u[n]={role:'player',pass:'tenis',name:n,email:'',tel:''});return u;}
const USERS=buildUsers();let currentUser=null;
function groupName(g){return 'Grupo '+g;}
function validSet(a,b){if(a==null||b==null||isNaN(a)||isNaN(b))return false;const hi=Math.max(a,b),lo=Math.min(a,b);if(hi===6&&lo<=4)return true;if(hi===7&&(lo===5||lo===6))return true;return false;}
function validSTB(a,b){return (a===1&&b===0)||(a===0&&b===1);}
function validMatch(s){if(s.length<2)return{ok:false,msg:'Un partido necesita al menos 2 sets.'};if(!validSet(s[0][0],s[0][1]))return{ok:false,msg:'Set 1 inválido (6-0 a 6-4, 7-5 o 7-6).'};if(!validSet(s[1][0],s[1][1]))return{ok:false,msg:'Set 2 inválido (6-0 a 6-4, 7-5 o 7-6).'};let w1=0,w2=0;[s[0],s[1]].forEach(([a,b])=>{if(a>b)w1++;else w2++;});if(w1===w2){if(s.length!==3)return{ok:false,msg:'Sets 1-1: falta el supertiebreak (1-0 o 0-1).'};if(!validSTB(s[2][0],s[2][1]))return{ok:false,msg:'El supertiebreak solo puede ser 1-0 o 0-1.'};}else if(s.length===3)return{ok:false,msg:'Ya hay ganador en 2 sets: no corresponde tercer set.'};return{ok:true};}
function findLoc(name,cycN){const c=cycles[cycN-1];if(!c.groups)return null;for(let gi=0;gi<c.groups.length;gi++){if(c.groups[gi].players.indexOf(name)>=0)return{g:gi+1};}return null;}
function getActive(){return cycles[activeN-1];}
function getInitials(n){if(!n)return'?';return n.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();}
function computeStats(cycN,gid){const g=cycles[cycN-1].groups[gid-1];const players=g.players;const st=players.map((name,i)=>({idx:i,name,pts:0,g:0,p:0,nj:0,sg:0,sp:0}));const byName={};st.forEach(s=>byName[s.name]=s);matches.filter(m=>!m.po&&m.cycle===cycN&&m.g===gid&&m.status==='confirmed').forEach(m=>{const a=byName[m.aName],b=byName[m.bName];if(!a||!b)return;let w1=0,w2=0;m.sets.forEach(([x,y])=>{if(x>y)w1++;else w2++;a.sg+=x;a.sp+=y;b.sg+=y;b.sp+=x;});if(w1>w2){a.g++;b.p++;a.pts+=3;b.pts+=1;}else{b.g++;a.p++;b.pts+=3;a.pts+=1;}});st.sort((x,y)=>y.pts-x.pts||y.g-x.g||(y.sg-y.sp)-(x.sg-x.sp));return st;}
function findMatch(cycN,gid,n1,n2){return matches.find(m=>!m.po&&m.cycle===cycN&&m.g===gid&&((m.aName===n1&&m.bName===n2)||(m.aName===n2&&m.bName===n1)));}
function pairsNeeded(c){let t=0;c.groups.forEach(g=>{const n=g.players.length;t+=n*(n-1)/2;});return t;}
function computeGeneral(){const tot={};cycles.forEach(c=>{if(!c.groups)return;c.groups.forEach((g,gi)=>{const st=computeStats(c.n,gi+1);st.forEach((s,pos)=>{const v=ptsForPos(gi+1,pos)+(pos===0?2:0);tot[s.name]=(tot[s.name]||0)+v;});});});return Object.entries(tot).map(([name,total])=>({name,total})).sort((a,b)=>b.total-a.total);}
function demoFill(){const c=getActive();const opts=[[[6,3],[6,4]],[[6,2],[4,6],[1,0]],[[7,5],[6,4]],[[6,4],[7,6]]];c.groups.forEach((g,gi)=>{const gid=gi+1;const pl=g.players;for(let i=0;i<pl.length;i++)for(let j=i+1;j<pl.length;j++){if(findMatch(activeN,gid,pl[i],pl[j]))continue;const w=Math.random()<0.5;const club=Math.random()<0.6?'Sohail':'Haza';const base=opts[Math.floor(Math.random()*opts.length)];matches.push({id:matchId++,cycle:activeN,g:gid,aName:pl[i],bName:pl[j],sets:w?base:base.map(([a,b])=>[b,a]),date:'2026-07-01',status:'confirmed',reporter:pl[i],club,locked:true});}});}
function allCyclesDone(){return cycles.every(c=>c.groups&&c.status==='finished');}
// PLAYOFF
function splitTramos(qual,T){const n=qual.length;const base=Math.floor(n/T);let extra=n%T;const out=[];let idx=0;for(let t=0;t<T;t++){const size=base+(t<extra?1:0);out.push(qual.slice(idx,idx+size));idx+=size;}return out;}
function seedOrder(n){if(n===1)return[0];const prev=seedOrder(n/2);const res=[];prev.forEach(p=>{res.push(p);res.push(n-1-p);});return res;}
function buildRounds(seeds){let size=1;while(size<seeds.length)size*=2;if(size<2)size=2;const order=seedOrder(size);const slots=new Array(size).fill(null);order.forEach((pos,k)=>{slots[k]=seeds[pos]!==undefined?seeds[pos]:null;});const rounds=[];let cur=[];for(let k=0;k<size;k+=2)cur.push({a:slots[k],b:slots[k+1],w:null,sets:null,locked:false,sid:[slots[k]?seeds.indexOf(slots[k])+1:'',slots[k+1]?seeds.indexOf(slots[k+1])+1:'']});rounds.push(cur);let cnt=cur.length;while(cnt>1){cnt/=2;rounds.push(Array.from({length:cnt},()=>({a:null,b:null,w:null,sets:null,locked:false,sid:['','']})));}rounds[0].forEach(m=>{if(m.a&&!m.b)m.w=m.a;if(m.b&&!m.a)m.w=m.b;});return rounds;}
function propagate(r){for(let ri=0;ri<r.length-1;ri++){const nx=r[ri+1];r[ri].forEach((m,mi)=>{const sl=nx[Math.floor(mi/2)];if(mi%2===0)sl.a=m.w;else sl.b=m.w;});}}
function applyStored(key,r){for(let p=0;p<r.length+1;p++){r.forEach(rd=>rd.forEach(m=>{if(m.a&&m.b&&!m.w){const k=key+'#'+[m.a,m.b].sort().join('|');const st=playoff.results[k];if(st){m.sets=st.sets;m.w=st.w;m.locked=true;}}}));propagate(r);}}
function loserOf(m){return m.w&&m.a&&m.b?(m.w===m.a?m.b:m.a):null;}
function label(i){return String.fromCharCode(65+i);}
function rebuildTramo(t){const tr=playoff.tramos[t];if(!tr)return;tr.main=buildRounds(tr.seeds);applyStored(t,tr.main);const losers=tr.main[0].map(loserOf).filter(Boolean);tr.cons=losers.length>=2?buildRounds(losers):null;if(tr.cons)applyStored(t+'c',tr.cons);}
function rebuildAll(){playoff.tramos.forEach((_,t)=>rebuildTramo(t));}
function buildTramosFromGeneral(T){const gen=computeGeneral().map(x=>x.name);const slices=splitTramos(gen,T);return{numTramos:T,results:{},viewT:0,qualified:gen,tramos:slices.map((s,i)=>({label:label(i),seeds:s.slice(),main:null,cons:null}))};}
function previewPlayoff(){if(!allCyclesDone())return false;const T=playoff.numTramos||4;playoff=Object.assign({started:false,preview:true},buildTramosFromGeneral(T));rebuildAll();return true;}
function confirmPlayoff(){if(!playoff.preview&&!playoff.started)return false;playoff.started=true;playoff.preview=false;return true;}
function startPlayoff(){if(!allCyclesDone())return false;const T=playoff.numTramos||4;playoff=Object.assign({started:true,preview:false},buildTramosFromGeneral(T));rebuildAll();return true;}
function setNumTramos(T){playoff.numTramos=T;if(playoff.started||playoff.preview){const gen=playoff.qualified;const slices=splitTramos(gen,T);playoff.results={};playoff.viewT=0;playoff.tramos=slices.map((s,i)=>({label:label(i),seeds:s.slice(),main:null,cons:null}));rebuildAll();}}
function removeSeed(t,name){const tr=playoff.tramos[t];tr.seeds=tr.seeds.filter(n=>n!==name);rebuildTramo(t);}
function addSeed(t,name){const tr=playoff.tramos[t];if(name&&!tr.seeds.includes(name))tr.seeds.push(name);rebuildTramo(t);}
function tramoOf(name){for(let t=0;t<playoff.tramos.length;t++)if(playoff.tramos[t].seeds.includes(name))return t;return -1;}
// GROUP EDIT
function movePlayer(name,fromG,toG){if(fromG===toG)return;const a=cycles[activeN-1].groups[fromG-1].players;const i=a.indexOf(name);if(i<0)return;a.splice(i,1);cycles[activeN-1].groups[toG-1].players.push(name);}
function removePlayerCycle(name,fromG){const a=cycles[activeN-1].groups[fromG-1].players;const i=a.indexOf(name);if(i>=0)a.splice(i,1);}


function initLogin(){const s=document.getElementById('login-user');s.innerHTML='<option value="">Seleccioná tu usuario</option><option value="admin">admin (Organización)</option>';if(LOGINMODE==='alpha'){ALLNAMES.slice().sort((a,b)=>a.localeCompare(b,'es')).forEach(n=>s.add(new Option(n,n)));}else{const c=cycles[activeN-1];const grps=(c&&c.groups)?c.groups:C1.map(p=>({players:[...p]}));grps.forEach((g,i)=>{const og=document.createElement('optgroup');og.label='Grupo '+(i+1);g.players.forEach(n=>og.appendChild(new Option(n,n)));s.appendChild(og);});}}
function doLogin(){const u=document.getElementById('login-user').value,p=document.getElementById('login-pass').value,e=document.getElementById('login-err');if(!u||!USERS[u]){e.textContent='Seleccioná un usuario válido.';e.style.display='block';return;}if(USERS[u].pass!==p){e.textContent='Contraseña incorrecta.';e.style.display='block';return;}currentUser=USERS[u];e.style.display='none';document.getElementById('login-screen').style.display='none';document.getElementById('main-app').style.display='block';document.getElementById('cur-name').textContent=currentUser.name;document.getElementById('cur-role').innerHTML=currentUser.role==='admin'?'<span class="role-badge">Admin</span>':'Jugador';if(currentUser.role==='player'){const loc=findLoc(currentUser.name,activeN);if(loc)selGroup=loc.g;}viewCycle=activeN;renderShell();showSub('grupos');}
function doLogout(){currentUser=null;document.getElementById('main-app').style.display='none';document.getElementById('login-screen').style.display='block';document.getElementById('login-pass').value='';initLogin();}
function renderShell(){renderCycleBar();renderSubTabs();}
function renderCycleBar(){const bar=document.getElementById('cycle-bar');let html='';cycles.forEach(c=>{const playable=!!c.groups;const isView=viewCycle===c.n;const icon=c.status==='finished'?'<i class="ti ti-circle-check st"></i>':c.status==='active'?'<i class="ti ti-player-play st"></i>':'<i class="ti ti-lock st"></i>';html+=`<button class="cycle-tab ${playable?'':'locked'} ${isView?'active':''}" onclick="${playable?`viewCyc(${c.n})`:''}">${icon} Ciclo ${c.n}</button>`;});const showPO=playoff.started||(playoff.preview&&currentUser.role==='admin');html+=`<button class="cycle-tab ${showPO?'':'locked'} ${viewCycle==='po'?'active':''}" onclick="${showPO?`viewCyc('po')`:''}">${showPO?(playoff.started?'<i class="ti ti-tournament st"></i> Play Offs':'<i class="ti ti-eye st"></i> Play Offs (previa)'):'<i class="ti ti-lock st"></i> Play Offs'}</button>`;bar.innerHTML=html;}
function renderSubTabs(){const tabs=document.getElementById('tabs');if(viewCycle==='po'){tabs.style.display='none';return;}tabs.style.display='flex';let t=[{id:'grupos',i:'ti-layout-grid',l:'Grupos'},{id:'general',i:'ti-chart-bar',l:'Clasificación'},{id:'cargar',i:'ti-upload',l:currentUser.role==='admin'?'Cargar/Disputas':'Cargar'},{id:'pendientes',i:'ti-bell',l:'Pendientes',b:true},{id:'perfil',i:'ti-user',l:'Perfil'}];if(currentUser.role==='admin')t.push({id:'admin',i:'ti-settings',l:'Admin'});tabs.innerHTML=t.map(x=>`<button class="tab${subView===x.id?' active':''}" id="tab-${x.id}" onclick="showSub('${x.id}')"><i class="ti ${x.i}" aria-hidden="true"></i> ${x.l}${x.b?' <span class="tab-n" id="pend-n">0</span>':''}</button>`).join('');}
function viewCyc(n){viewCycle=n;if(n==='po'){renderShell();showPlayoffView();}else{renderShell();showSub('grupos');}}
function showSub(name){if(viewCycle==='po')viewCycle=activeN;subView=name;['grupos','general','cargar','pendientes','admin','playoff','perfil'].forEach(v=>{const el=document.getElementById('view-'+v);if(el)el.style.display='none';});document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));var tb=document.getElementById('tab-'+name);if(tb)tb.classList.add('active');document.getElementById('view-'+name).style.display='block';if(name==='grupos')renderGrupos();if(name==='general')renderGeneral();if(name==='cargar'){populateForm();renderCargarDisputas();}if(name==='pendientes')renderPend();if(name==='admin')renderAdmin();if(name==='perfil')renderPerfil();updateHdr();}
function updateHdr(){document.getElementById('hdr-sub').textContent=viewCycle==='po'?'Play Offs':`Ciclo ${viewCycle} · ${FECHAS[viewCycle-1]} · ${cycles[viewCycle-1].status}`;}
function groupCardHTML(gid){const c=cycles[viewCycle-1];const isActive=c.status==='active';const grp=c.groups[gid-1];const st=computeStats(viewCycle,gid);const dest=DESTINO[gid];const players=grp.players;const fc={};players.forEach(p=>{const f=p.split(' ')[0];fc[f]=(fc[f]||0)+1;});const lbl=p=>{const f=p.split(' ')[0];return fc[f]>1?p:f;};let cls=st.map((s,i)=>{const d=dest[i]||'',dn=parseInt((d||'G99').replace('G',''));const ar=dn<gid?'dest-up':dn>gid?'dest-down':'dest-same';const ic=dn<gid?'↑':dn>gid?'↓':'=';const ex=i===0?2:0;const base=ptsForPos(gid,i);return `<tr class="${i===0?'winner-row':''}"><td>${d?`<span class="dest ${ar}">${ic}${groupName(dn)}</span>`:''}</td><td><span class="avatar">${getInitials(s.name)}</span>${s.name}</td><td><strong>${s.pts}</strong></td><td>${s.g}</td><td>${s.p}</td><td>${s.nj}</td><td>${s.sg}</td><td>${s.sp}</td><td>${s.sg-s.sp}</td><td>${base}</td><td>${ex>0?ex:''}</td><td><strong>${base+ex}</strong></td></tr>`;}).join('');const head=players.map(p=>`<th>${lbl(p)}</th>`).join('');let mrows=players.map((p,i)=>{const cols=players.map((q,j)=>{if(i===j)return`<td class="res-black"></td>`;const m=findMatch(viewCycle,gid,p,q);if(m&&m.status==='confirmed'){const sc=m.aName===p?m.sets.map(([a,b])=>`${a}-${b}`).join(' '):m.sets.map(([a,b])=>`${b}-${a}`).join(' ');return`<td class="${m.club==='Haza'?'cell-haza':'cell-sohail'}" onclick="openModal(${m.id})">${sc}</td>`;}if(m&&m.status==='pending'){const sc=m.aName===p?m.sets.map(([a,b])=>`${a}-${b}`).join(' '):m.sets.map(([a,b])=>`${b}-${a}`).join(' ');return`<td class="cell-pending" onclick="openModal(${m.id})">${sc}⏳</td>`;}if(m&&m.status==='disputed')return`<td class="cell-disputed" onclick="openModal(${m.id})">disp.</td>`;if(isActive&&canCreate(gid,p,q))return`<td class="cell-empty" onclick="prefill(${gid},'${esc(p)}','${esc(q)}')">+</td>`;return`<td class="cell-locked">·</td>`;}).join('');return`<tr><td>${lbl(p)}</td>${cols}</tr>`;}).join('');return`<div class="card grp-card"><div class="grp-title">Clasificación ${groupName(gid)}</div><div class="overflow-x"><table class="cls-table"><thead><tr class="clg-head"><th colspan="9"></th><th colspan="3">Puntos para la Clasificación General</th></tr><tr><th>Destino</th><th>Jugador</th><th>Pts</th><th>G</th><th>P</th><th>NJ</th><th>SG</th><th>SP</th><th>Bal</th><th>P.puesto</th><th>Extra</th><th>Total</th></tr></thead><tbody>${cls}</tbody></table></div><p class="legend-txt">* <b>Pts</b>: puntos del grupo (3 victoria, 1 derrota, 0 no jugado). <b>G</b>: ganados. <b>P</b>: perdidos. <b>NJ</b>: no jugados. <b>SG</b>: sets ganados. <b>SP</b>: sets perdidos. <b>Bal</b>: balance de sets (SG−SP), desempata. <b>Destino</b>: grupo al que sube (↑), baja (↓) o se mantiene (=). <b>P.puesto</b>+<b>Extra</b> (+2 al ganador del grupo) = <b>Total</b> a la Clasificación General.</p><div class="section-lbl">Resultados ${groupName(gid)}</div><div class="overflow-x"><table class="res-table"><thead><tr><th>Jugadores</th>${head}</tr></thead><tbody>${mrows}</tbody></table></div><p class="legend-txt">El marcador se lee en la fila del jugador (sus juegos primero). Celeste = jugado en Sohail · naranja = jugado en Haza.</p></div>`;}
function esc(s){return String(s).replace(/'/g,"\\'");}
function renderGrupos(){const c=cycles[viewCycle-1];let html='';if(LAYOUT==='selector'){html+=`<div class="card"><div class="section-lbl">Elegí el grupo</div><div class="grp-pick">`+c.groups.map((g,i)=>{const gid=i+1;const mine=currentUser.role==='player'&&findLoc(currentUser.name,viewCycle)&&findLoc(currentUser.name,viewCycle).g===gid;return `<button class="grp-btn ${selGroup===gid?'active':''}" onclick="setSelGroup(${gid})">${groupName(gid)}${mine?'<span class="mine">tuyo</span>':''}</button>`;}).join('')+`</div></div>`;if(selGroup>c.groups.length)selGroup=1;html+=groupCardHTML(selGroup);}else{c.groups.forEach((g,gi)=>{html+=groupCardHTML(gi+1);if(gi<c.groups.length-1)html+='<div class="grp-sep"></div>';});}html+=`<div class="card legend-card"><div class="legend"><span><span class="dot" style="background:var(--sohail)"></span> Sohail</span><span><span class="dot" style="background:var(--haza)"></span> Haza</span><span><span class="dot dot-pend"></span> Pendiente</span><span><span class="dot" style="background:#FCEBEB"></span> Disputado</span><span>+ cargar · · no editable</span></div></div>`;document.getElementById('view-grupos').innerHTML=html;}
function setSelGroup(g){selGroup=g;renderGrupos();}
function canCreate(gid,n1,n2){if(viewCycle!==activeN)return false;if(currentUser.role==='admin')return true;const loc=findLoc(currentUser.name,activeN);return loc&&loc.g===gid&&(currentUser.name===n1||currentUser.name===n2);}
function renderGeneral(){const all=computeGeneral();const pc=['p1','p2','p3'];document.getElementById('gen-body').innerHTML=all.map((p,i)=>{const me=currentUser.role==='player'&&p.name===currentUser.name;const loc=findLoc(p.name,activeN);return`<tr class="${me?'me-row':''}"><td><span class="pos ${pc[i]||'pn'}">${i+1}</span></td><td><span class="avatar">${getInitials(p.name)}</span>${p.name}${me?' <span class="badge badge-ok">Vos</span>':''}</td><td>${loc?groupName(loc.g):'—'}</td><td><strong>${p.total}</strong></td></tr>`;}).join('');}
function pickClub(c){formClub=c;document.getElementById('club-sohail').className='club-opt'+(c==='Sohail'?' sel-sohail':'');document.getElementById('club-haza').className='club-opt'+(c==='Haza'?' sel-haza':'');document.getElementById('club-pick').classList.remove('req-empty');}
function populateForm(gid,na,nb){poContext=null;formClub='';const r=document.getElementById('f-reporter'),o=document.getElementById('f-rival'),note=document.getElementById('cargar-note');r.innerHTML='<option value="">—</option>';o.innerHTML='<option value="">—</option>';const c=getActive();if(currentUser.role==='player'){const loc=findLoc(currentUser.name,activeN);if(!loc){note.textContent='No estás en el ciclo activo.';return;}r.add(new Option(currentUser.name,currentUser.name));r.value=currentUser.name;r.disabled=true;c.groups[loc.g-1].players.forEach(j=>{if(j!==currentUser.name)o.add(new Option(j,j));});note.textContent=`Cargás partidos tuyos del ${groupName(loc.g)}. Tu rival debe confirmarlo. Una vez validado no se reedita.`;}else{r.disabled=false;c.groups.forEach((g,gi)=>g.players.forEach(j=>{r.add(new Option(`[${groupName(gi+1)}] ${j}`,`${gi+1}|${j}`));o.add(new Option(`[${groupName(gi+1)}] ${j}`,`${gi+1}|${j}`));}));note.textContent=`Admin: cargás/editás cualquier partido. Lo que cargás queda validado.`;if(gid!=null){r.value=`${gid}|${na}`;o.value=`${gid}|${nb}`;}}
document.getElementById('club-sohail').className='club-opt';document.getElementById('club-haza').className='club-opt';document.getElementById('f-fecha').value='';}
function prefill(gid,n1,n2){showSub('cargar');if(currentUser.role==='player'){document.getElementById('f-rival').value=(currentUser.name===n1?n2:n1);}else{document.getElementById('f-reporter').value=`${gid}|${n1}`;document.getElementById('f-rival').value=`${gid}|${n2}`;}}
function readSets(){const s=[[+document.getElementById('s1a').value,+document.getElementById('s1b').value],[+document.getElementById('s2a').value,+document.getElementById('s2b').value]];if(document.getElementById('s3-row').style.display!=='none')s.push([+document.getElementById('s3a').value,+document.getElementById('s3b').value]);return s;}
function parseSel(v){if(v.indexOf('|')>=0){const p=v.split('|');return{g:+p[0],name:p[1]};}return{g:null,name:v};}
function submitResult(){const rv=document.getElementById('f-reporter').value,iv=document.getElementById('f-rival').value,fecha=document.getElementById('f-fecha').value;if(!rv||!iv){fAlert('Seleccioná los dos jugadores.','err');return;}let repName,rivName,gid;if(currentUser.role==='player'){repName=currentUser.name;rivName=iv;const loc=findLoc(repName,activeN);gid=loc.g;}else{const a=parseSel(rv),b=parseSel(iv);if(a.g!==b.g){fAlert('Ambos deben ser del mismo grupo.','err');return;}gid=a.g;repName=a.name;rivName=b.name;}if(repName===rivName){fAlert('Elegí dos jugadores distintos.','err');return;}if(!formClub){fAlert('Elegí el club (Sohail o Haza).','err');document.getElementById('club-pick').classList.add('req-empty');return;}if(!fecha){fAlert('Completá la fecha del partido.','err');document.getElementById('f-fecha').classList.add('req-empty');return;}const ex=findMatch(activeN,gid,repName,rivName);if(ex&&ex.locked&&currentUser.role!=='admin'){fAlert('Ese resultado ya fue validado. Solo el admin puede editarlo.','err');return;}const s=readSets();const v=validMatch(s);if(!v.ok){fAlert('✕ '+v.msg,'err');return;}matches=matches.filter(m=>!(m.cycle===activeN&&m.g===gid&&!m.po&&((m.aName===repName&&m.bName===rivName)||(m.aName===rivName&&m.bName===repName))));const isAdmin=currentUser.role==='admin';matches.push({id:matchId++,cycle:activeN,g:gid,aName:repName,bName:rivName,sets:s,date:fecha,status:isAdmin?'confirmed':'pending',reporter:repName,club:formClub,locked:isAdmin});clearForm();fAlert(isAdmin?'✓ Resultado válido y validado (admin).':'✓ Resultado válido enviado. El rival debe confirmarlo.','ok');renderPend();renderCycleBar();}
function fAlert(m,t){const e=document.getElementById('form-alert');e.className=`alert alert-${t}`;e.textContent=m;setTimeout(()=>{e.textContent='';e.className='';},6000);}
function clearForm(){if(currentUser.role==='admin')document.getElementById('f-reporter').value='';document.getElementById('f-rival').value='';['s1a','s1b','s2a','s2b','s3a','s3b'].forEach(id=>{const e=document.getElementById(id);if(e)e.value='';});document.getElementById('s3-row').style.display='none';formClub='';document.getElementById('club-sohail').className='club-opt';document.getElementById('club-haza').className='club-opt';document.getElementById('f-fecha').value='';document.getElementById('club-pick').classList.remove('req-empty');document.getElementById('f-fecha').classList.remove('req-empty');}
function involvedPend(m){if(currentUser.role==='admin')return true;if(m.po)return m.poNames&&m.poNames.includes(currentUser.name)&&m.reporter!==currentUser.name;return (m.aName===currentUser.name||m.bName===currentUser.name)&&m.reporter!==currentUser.name;}
function renderPend(){const pend=matches.filter(m=>m.status==='pending');const vis=pend.filter(m=>{if(currentUser.role==='admin')return true;if(m.po)return m.poNames&&m.poNames.includes(currentUser.name);return m.aName===currentUser.name||m.bName===currentUser.name;});const pn=document.getElementById('pend-n');const mine=pend.filter(involvedPend);if(pn)pn.textContent=currentUser.role==='admin'?pend.length:mine.length;if(!vis.length){document.getElementById('pend-list').innerHTML='<div class="empty">No hay pendientes</div>';return;}document.getElementById('pend-list').innerHTML=vis.map(m=>{let p1,p2,tag;if(m.po){p1=m.poNames[0];p2=m.poNames[1];tag='Play Off '+m.tLabel;}else{p1=m.aName;p2=m.bName;tag=`C${m.cycle}·${groupName(m.g)}`;}const sc=m.sets.map(([a,b])=>`${a}-${b}`).join(' / ');const ca=involvedPend(m);const wait=currentUser.role==='player'&&m.reporter===currentUser.name;return`<div class="pend-item"><span class="badge badge-tag">${tag}</span><span class="pend-nm">${p1}</span><span class="pend-sc">${sc}</span><span class="pend-nm">${p2}</span>${m.club?`<span class="badge ${m.club==='Haza'?'badge-haza':'badge-sohail'}">${m.club}</span>`:''}<span class="badge badge-pend">Pendiente</span>${wait?'<span class="lock-note">Esperando al rival</span>':''}${ca?`<div class="pend-act"><button class="btn btn-accent btn-sm" onclick="openModal(${m.id})"><i class="ti ti-eye"></i> Revisar</button></div>`:''}</div>`;}).join('');}
function openModal(mid){const m=matches.find(x=>x.id===mid);if(!m)return;currentModal=mid;let p1,p2,rep,tag;if(m.po){p1=m.poNames[0];p2=m.poNames[1];rep=m.reporter;tag='Play Off '+m.tLabel;}else{p1=m.aName;p2=m.bName;rep=m.reporter;tag=`C${m.cycle} ${groupName(m.g)}`;}const sc=m.sets.map(([a,b])=>`${a}-${b}`).join(' / ');document.getElementById('modal-title').textContent=(m.status==='confirmed'?'Resultado validado':m.status==='disputed'?'Resultado disputado':'Revisar resultado')+` · ${tag}`;document.getElementById('modal-body').innerHTML=`<p class="modal-rep">Reportado por <strong>${rep}</strong>${m.club?` · Club <strong>${m.club}</strong>`:''}</p><div class="modal-score ${m.club==='Haza'?'ms-haza':'ms-sohail'}"><p>${p1} ${sc} ${p2}</p></div><p class="modal-meta">Fecha: ${m.date} · Estado: ${m.status}${m.locked?' · 🔒 validado':''}</p>`;const acts=document.getElementById('modal-actions');let h='';const canAct=involvedPend(m)&&m.status==='pending';if(canAct)h+=`<button class="btn btn-success" onclick="confirmM()"><i class="ti ti-check"></i> Confirmar</button><button class="btn btn-danger" onclick="disputeM()"><i class="ti ti-x"></i> Disputar</button>`;if(currentUser.role==='admin'&&!m.po)h+=`<button class="btn btn-primary" onclick="adminEdit(${mid})"><i class="ti ti-edit"></i> Editar</button>`;else if(m.status==='confirmed'&&!m.po)h+=`<span class="lock-note" style="align-self:center">Validado — solo el admin edita</span>`;h+=`<button class="btn" onclick="closeM()">Cerrar</button>`;acts.innerHTML=h;document.getElementById('modal-bg').classList.add('open');}
function closeM(){document.getElementById('modal-bg').classList.remove('open');}
function confirmM(){const m=matches.find(x=>x.id===currentModal);if(m){m.status='confirmed';m.locked=true;if(m.po)applyPoPending(m);}closeM();refreshAll();toast('¡Resultado confirmado y validado!');}
function disputeM(){const m=matches.find(x=>x.id===currentModal);if(m)m.status='disputed';closeM();refreshAll();toast('Resultado disputado. El admin lo revisará.');}
function adminEdit(mid){const m=matches.find(x=>x.id===mid);closeM();showSub('cargar');document.getElementById('f-reporter').value=`${m.g}|${m.aName}`;document.getElementById('f-rival').value=`${m.g}|${m.bName}`;pickClub(m.club);['s1a','s1b','s2a','s2b','s3a','s3b'].forEach(id=>document.getElementById(id).value='');document.getElementById('s3-row').style.display='none';m.sets.forEach((s,i)=>{const a=document.getElementById(`s${i+1}a`),b=document.getElementById(`s${i+1}b`);if(a)a.value=s[0];if(b)b.value=s[1];if(i===2)document.getElementById('s3-row').style.display='flex';});document.getElementById('f-fecha').value=m.date;}
function renderAdmin(){const c=getActive();const need=pairsNeeded(c);const done=matches.filter(m=>m.cycle===activeN&&!m.po&&m.status==='confirmed').length;const notC=matches.filter(m=>m.cycle===activeN&&!m.po&&m.status!=='confirmed').length;const ready=done>=need&&notC===0;const cyclesDone=allCyclesDone();let h=`<div class="card"><div class="section-lbl">Estado del ciclo</div><div class="alert ${ready?'alert-ok':'alert-info'}">Ciclo ${activeN}: ${done}/${need} partidos validados${notC>0?` · ${notC} sin validar`:''}. ${ready?'✓ Listo para cerrar el ciclo.':'Faltan validar resultados.'}</div><div class="gap-sm mt-sm">${activeN<3?`<button class="btn btn-accent" ${(!ready)?'disabled':''} onclick="startNextCycle()"><i class="ti ti-arrow-right-circle"></i> Cerrar ciclo e iniciar siguiente</button>`:`<button class="btn btn-accent" ${(!ready||getActive().status==='finished')?'disabled':''} onclick="finishLastCycle()"><i class="ti ti-flag-check"></i> Finalizar último ciclo (habilita Play Offs)</button>`}<button class="btn" onclick="demoFillUI()"><i class="ti ti-wand"></i> Simular y validar todos</button><button class="btn" onclick="forceConfirmAll()"><i class="ti ti-checks"></i> Confirmar pendientes</button></div></div>`;
h+=`<div class="card"><div class="section-lbl">Editar grupos (Ciclo ${activeN})</div><p class="legend-txt" style="margin-top:0">Reasigná, quitá o agregá jugadores. Podés dejar grupos de distinto tamaño si hace falta. Cuando se agrega gente a un grupo, después manejás cómo suben/bajan con los menús de cada jugador.</p><div class="req-wrap" style="margin-bottom:.7rem"><div class="section-lbl" style="margin-top:0">Agregar jugador</div><div class="form-row" style="grid-template-columns:1fr 1fr 1fr auto;align-items:end"><div class="form-group"><label>Nombre</label><input id="ap-nom" placeholder="Nombre"></div><div class="form-group"><label>Apellido</label><input id="ap-ape" placeholder="Apellido"></div><div class="form-group"><label>Grupo</label><select id="ap-grp">${c.groups.map((_,k)=>`<option value="${k+1}">${groupName(k+1)}</option>`).join('')}</select></div><div class="form-group"><button class="btn btn-primary" onclick="addPlayerUI()"><i class="ti ti-user-plus"></i> Agregar</button></div></div></div><div class="grpedit">`+c.groups.map((g,gi)=>{const gid=gi+1;return `<div class="ge-group"><div class="ge-gtitle">${groupName(gid)} (${g.players.length})</div>`+g.players.map(n=>`<div class="ge-row"><span class="ge-nm">${n}</span><select class="ge-sel" onchange="movePlayerUI('${esc(n)}',${gid},this.value)"><option value="">mover a…</option>${c.groups.map((_,k)=>k+1!==gid?`<option value="${k+1}">${groupName(k+1)}</option>`:'').join('')}</select><button class="btn btn-danger btn-sm" onclick="removePlayerUI('${esc(n)}',${gid})">Quitar</button></div>`).join('')+`</div>`;}).join('')+`</div></div>`;
h+=`<div class="card"><div class="section-lbl">Fechas de los ciclos</div><div class="form-row" style="grid-template-columns:1fr 1fr 1fr">${[0,1,2].map(i=>`<div class="form-group"><label>Ciclo ${i+1}</label><input type="text" value="${FECHAS[i].replace(/"/g,'&quot;')}" onchange="setFecha(${i},this.value)"></div>`).join('')}</div><p class="legend-txt" style="margin-top:0">Editá el período de cada ciclo (texto libre, ej. "15/06/26 – 19/07/26").</p></div>`;
h+=destinoCard();h+=`<div class="card"><div class="section-lbl">Play Offs</div>${cyclesDone?'<div class="alert alert-ok">Los 3 ciclos están cerrados. Previsualizá los cuadros para revisarlos y ajustar quién juega antes de iniciarlos.</div>':'<div class="alert alert-info">Los Play Offs se habilitan cuando los 3 ciclos estén cerrados.</div>'}<div class="form-row"><div class="form-group"><label>¿Cuántos cuadros (playoffs) en total?</label><select id="po-num" onchange="setPoNum(this.value)">${[1,2,3,4,5,6].map(k=>`<option value="${k}" ${playoff.numTramos===k?'selected':''}>${k} cuadro${k>1?'s':''}</option>`).join('')}</select></div><div class="form-group" style="align-self:end"><button class="btn btn-primary" ${cyclesDone&&!playoff.started?'':'disabled'} onclick="previewPlayoffUI()"><i class="ti ti-eye"></i> Previsualizar Play Offs</button></div></div>${playoff.started?'<p class="legend-txt">Los Play Offs ya están iniciados. Gestionalos desde la pestaña Play Offs.</p>':playoff.preview?'<p class="legend-txt">Hay una previsualización en curso: revisala y confirmá el inicio en la pestaña <b>Play Offs</b>.</p>':''}</div>`;
const disp=[];
document.getElementById('view-admin').innerHTML=h;}
function movePlayerUI(name,fromG,toG){if(!toG)return;movePlayer(name,fromG,+toG);renderAdmin();toast(name+' movido a '+groupName(+toG));}
function removePlayerUI(name,fromG){removePlayerCycle(name,fromG);renderAdmin();toast(name+' quitado del ciclo.');}
function setPoNum(v){playoff.numTramos=+v;if(playoff.started||playoff.preview){setNumTramos(+v);}}
function finishLastCycle(){const c=getActive();const need=pairsNeeded(c);const done=matches.filter(m=>m.cycle===activeN&&!m.po&&m.status==='confirmed').length;const notC=matches.filter(m=>m.cycle===activeN&&!m.po&&m.status!=='confirmed').length;if(done<need||notC>0){toast('Faltan validar resultados del ciclo.');return;}c.status='finished';renderShell();renderAdmin();toast('Último ciclo finalizado. Ya podés previsualizar los Play Offs.');}
function addPlayerUI(){const nom=(document.getElementById('ap-nom').value||'').trim();const ape=(document.getElementById('ap-ape').value||'').trim();const gid=+document.getElementById('ap-grp').value;const full=(nom+' '+ape).trim();if(!nom||!ape){toast('Completá nombre y apellido.');return;}if(!gid){toast('Elegí el grupo.');return;}if(USERS[full]){toast('Ya existe un jugador con ese nombre y apellido.');return;}addPlayerToCycle(full,gid);initLogin();renderAdmin();toast(full+' agregado al '+groupName(gid)+'.');}
function setDestino(gid,pos,val){ensureDestino(gid,pos+1);DESTINO[gid][pos]='G'+val;if(subView==='admin')renderAdmin();toast(groupName(gid)+' · '+(pos+1)+'º → '+groupName(+val));}
function destinoCard(){const grps=cycles[activeN-1].groups;return `<div class="card"><div class="section-lbl">Ascensos y descensos — a qué grupo pasa cada puesto</div><p class="legend-txt" style="margin-top:0">Para cada grupo, elegí a qué grupo va cada puesto al cerrar el ciclo. Las filas se ajustan solas a la cantidad de jugadores de cada grupo (si un grupo tiene 6, aparece el 6º puesto).</p><div class="grpedit">`+grps.map((g,gi)=>{const gid=gi+1;const len=Math.max(1,g.players.length);ensureDestino(gid,len);return `<div class="ge-group"><div class="ge-gtitle">${groupName(gid)} (${g.players.length})</div>`+[...Array(len)].map((_,pos)=>{const cur=parseInt((DESTINO[gid][pos]||('G'+Math.min(gid+1,12))).replace('G',''));return `<div class="ge-row"><span class="ge-nm">${pos+1}º →</span><select class="ge-sel" onchange="setDestino(${gid},${pos},this.value)">${[...Array(12)].map((_,k)=>`<option value="${k+1}" ${cur===k+1?'selected':''}>${groupName(k+1)}</option>`).join('')}</select></div>`;}).join('')+`</div>`;}).join('')+`</div></div>`;}
function setFecha(i,v){FECHAS[i]=v;updateHdr();renderCycleBar();toast('Fecha del Ciclo '+(i+1)+' actualizada.');}
function previewPlayoffUI(){if(!previewPlayoff()){toast('Primero cerrá los 3 ciclos.');return;}viewCycle='po';renderShell();showPlayoffView();toast('Previsualización lista. Ajustá los jugadores y confirmá el inicio.');}
function confirmPlayoffUI(){if(!confirmPlayoff())return;renderShell();showPlayoffView();toast('¡Play Offs iniciados! Ya son visibles para los jugadores.');}
function renderCargarDisputas(){const cont=document.getElementById('cargar-disputes');if(!cont)return;if(currentUser.role!=='admin'){cont.innerHTML='';return;}const disp=matches.filter(m=>m.status==='disputed');cont.innerHTML=`<div class="card"><div class="section-lbl">Disputas activas (resuelve el admin)</div>${disp.length?disp.map(m=>{let p1,p2;if(m.po){p1=m.poNames[0];p2=m.poNames[1];}else{p1=m.aName;p2=m.bName;}const sc=m.sets.map(([a,b])=>`${a}-${b}`).join(' / ');return`<div class="disp-item"><span class="badge badge-disp">${m.po?'PO '+m.tLabel:'C'+m.cycle+' '+groupName(m.g)}</span><span>${p1} ${sc} ${p2}</span><div class="disp-act"><button class="btn btn-success btn-sm" onclick="resolveD(${m.id})">Validar</button>${!m.po?`<button class="btn btn-primary btn-sm" onclick="adminEdit(${m.id})">Editar</button>`:''}</div></div>`;}).join(''):'<div class="empty">No hay disputas</div>'}</div>`;}
function resolveD(mid){const m=matches.find(x=>x.id===mid);if(m){m.status='confirmed';m.locked=true;if(m.po)applyPoPending(m);}refreshAll();toast('Disputa resuelta.');}
function forceConfirmAll(){matches.forEach(m=>{if(m.status==='pending'){m.status='confirmed';m.locked=true;if(m.po)applyPoPending(m);}});refreshAll();toast('Pendientes confirmados.');}
function demoFillUI(){demoFill();refreshAll();toast('Ciclo simulado y validado.');}
function startNextCycle(){const c=getActive();const need=pairsNeeded(c);const done=matches.filter(m=>m.cycle===activeN&&!m.po&&m.status==='confirmed').length;const notC=matches.filter(m=>m.cycle===activeN&&!m.po&&m.status!=='confirmed').length;if(done<need||notC>0){toast('Faltan validar resultados antes de cerrar.');return;}const buckets={};for(let k=1;k<=12;k++)buckets[k]=[];c.groups.forEach((g,gi)=>{const gid=gi+1;const st=computeStats(activeN,gid);ensureDestino(gid,st.length);const dest=DESTINO[gid];st.forEach((s,pos)=>{const d=dest[pos]||('G'+Math.min(gid+1,12));const dn=parseInt(d.replace('G',''));buckets[dn].push({name:s.name,total:ptsForPos(gid,pos)+(pos===0?2:0)});});});const ng=[];for(let k=1;k<=12;k++)ng.push({players:buckets[k].sort((a,b)=>b.total-a.total).map(x=>x.name)});c.status='finished';if(activeN<3){const nx=cycles[activeN];nx.groups=ng;nx.status='active';activeN=nx.n;viewCycle=nx.n;if(currentUser.role==='player'){const loc=findLoc(currentUser.name,activeN);if(loc)selGroup=loc.g;}toast(`Ciclo ${c.n} cerrado. ¡Ciclo ${nx.n} iniciado con grupos actualizados!`);}else{toast('Ciclo 3 cerrado. Ya podés iniciar los Play Offs desde Admin.');}renderShell();showSub('grupos');}
function renderPerfil(){const u=currentUser;const loc=u.role==='player'?findLoc(u.name,activeN):null;
if(u.role==='admin'){
  const players=ALLNAMES.map(n=>USERS[n]).filter(Boolean);
  let html=`<div class="card"><div class="section-lbl">Mi perfil — Administrador</div><div class="prof-row"><span>Nombre</span><span>${u.name}</span></div><div class="prof-row"><span>Rol</span><span>Administrador</span></div></div>
<div class="card"><div class="section-lbl">Cambiar mi contraseña</div><div id="pw-alert"></div><div class="form-row"><div class="form-group"><label>Contraseña actual</label><input type="password" id="pw-old"></div><div class="form-group"><label>Nueva contraseña</label><input type="password" id="pw-new"></div></div><div class="form-row"><div class="form-group"><label>Repetir nueva contraseña</label><input type="password" id="pw-new2"></div><div class="form-group" style="align-self:end"><button class="btn btn-accent" onclick="changePw()"><i class="ti ti-lock"></i> Guardar</button></div></div></div>
<div class="card"><div class="section-lbl">Gestión de jugadores — ver, editar y resetear contraseñas</div><p class="legend-txt" style="margin-top:0">Buscá por nombre o grupo. Podés editar nombre, email, teléfono y resetear la contraseña de cualquier jugador.</p>
<input type="text" id="player-search" placeholder="Buscar jugador…" oninput="filterPlayerList()" style="width:100%;padding:8px 10px;border-radius:8px;border:1px solid var(--border2);background:var(--surface);color:var(--text);font-size:13px;margin-bottom:.75rem">
<div id="player-list">${renderPlayerList(players)}</div></div>`;
  document.getElementById('view-perfil').innerHTML=html;
}else{
  const extra=u.email||u.tel?`<div class="prof-row"><span>Email</span><span>${u.email||'—'}</span></div><div class="prof-row"><span>Teléfono</span><span>${u.tel||'—'}</span></div>`:''
  document.getElementById('view-perfil').innerHTML=`<div class="card"><div class="section-lbl">Mi perfil</div><div id="edit-profile-alert"></div>
<div class="form-row"><div class="form-group"><label>Nombre completo</label><input type="text" id="pf-name" value="${esc(u.name)}"></div><div class="form-group"><label>Email</label><input type="email" id="pf-email" value="${esc(u.email||'')}"></div></div>
<div class="form-row"><div class="form-group"><label>Teléfono</label><input type="tel" id="pf-tel" value="${esc(u.tel||'')}"></div><div class="form-group" style="align-self:end"><button class="btn btn-accent" onclick="saveProfile()"><i class="ti ti-device-floppy"></i> Guardar datos</button></div></div>
${loc?`<div class="prof-row" style="margin-top:.5rem"><span>Grupo actual</span><span>${groupName(loc.g)}</span></div>`:''}
</div>
<div class="card"><div class="section-lbl">Cambiar contraseña</div><div id="pw-alert"></div>
<div class="form-row"><div class="form-group"><label>Contraseña actual</label><input type="password" id="pw-old"></div><div class="form-group"><label>Nueva contraseña</label><input type="password" id="pw-new"></div></div>
<div class="form-row"><div class="form-group"><label>Repetir nueva contraseña</label><input type="password" id="pw-new2"></div><div class="form-group" style="align-self:end"><button class="btn btn-accent" onclick="changePw()"><i class="ti ti-lock"></i> Guardar contraseña</button></div></div></div>`;
}}
function renderPlayerList(players,filter){const f=(filter||'').toLowerCase();const visible=players.filter(p=>p&&p.name&&(!f||p.name.toLowerCase().includes(f)));return visible.map(p=>{const loc=findLoc(p.name,activeN);return `<div class="ge-group" style="margin-bottom:.5rem"><div style="display:flex;justify-content:space-between;align-items:center"><div class="ge-gtitle">${p.name}${loc?' <span class="badge badge-tag">'+groupName(loc.g)+'</span>':''}</div><button class="btn btn-sm" onclick="togglePlayerEdit('${esc(p.name)}')"><i class="ti ti-edit"></i> Editar</button></div><div id="pe-${esc(p.name)}" style="display:none;margin-top:.5rem"><div class="form-row"><div class="form-group"><label>Nombre completo</label><input type="text" id="pe-name-${esc(p.name)}" value="${esc(p.name)}"></div><div class="form-group"><label>Email</label><input type="email" id="pe-email-${esc(p.name)}" value="${esc(p.email||'')}"></div></div><div class="form-row"><div class="form-group"><label>Teléfono</label><input type="tel" id="pe-tel-${esc(p.name)}" value="${esc(p.tel||'')}"></div><div class="form-group" style="align-self:end"><div class="gap-sm"><button class="btn btn-success btn-sm" onclick="savePlayerAdmin('${esc(p.name)}')"><i class="ti ti-device-floppy"></i> Guardar</button><button class="btn btn-danger btn-sm" onclick="resetPwd('${esc(p.name)}')"><i class="ti ti-refresh"></i> Resetear clave</button></div></div></div></div></div>`;}).join('') || '<div class="empty">Sin resultados</div>';}
function filterPlayerList(){const f=document.getElementById('player-search').value;const players=ALLNAMES.map(n=>USERS[n]).filter(Boolean);document.getElementById('player-list').innerHTML=renderPlayerList(players,f);}
function togglePlayerEdit(name){const el=document.getElementById('pe-'+name);if(el)el.style.display=el.style.display==='none'?'block':'none';}
function savePlayerAdmin(oldName){const newName=(document.getElementById('pe-name-'+oldName).value||'').trim();const email=(document.getElementById('pe-email-'+oldName).value||'').trim();const tel=(document.getElementById('pe-tel-'+oldName).value||'').trim();if(!newName){toast('El nombre no puede estar vacío.');return;}const u=USERS[oldName];if(!u)return;u.email=email;u.tel=tel;if(newName!==oldName){USERS[newName]={...u,name:newName};delete USERS[oldName];const idx=ALLNAMES.indexOf(oldName);if(idx>=0)ALLNAMES[idx]=newName;cycles.forEach(c=>{if(!c.groups)return;c.groups.forEach(g=>{const pi=g.players.indexOf(oldName);if(pi>=0)g.players[pi]=newName;});});}persist();renderPerfil();toast(newName+': datos actualizados.');}
function resetPwd(name){const u=USERS[name];if(!u)return;u.pass='tenis';persist();toast(name+': contraseña reseteada a "tenis".');}
function saveProfile(){const name=(document.getElementById('pf-name').value||'').trim();const email=(document.getElementById('pf-email').value||'').trim();const tel=(document.getElementById('pf-tel').value||'').trim();const a=document.getElementById('edit-profile-alert');if(!name){a.className='alert alert-err';a.textContent='El nombre no puede estar vacío.';return;}const u=currentUser;const oldName=u.name;u.email=email;u.tel=tel;if(name!==oldName){if(USERS[name]&&name!==oldName){a.className='alert alert-err';a.textContent='Ya existe un jugador con ese nombre.';return;}USERS[name]={...u,name};delete USERS[oldName];const idx=ALLNAMES.indexOf(oldName);if(idx>=0)ALLNAMES[idx]=name;cycles.forEach(c=>{if(!c.groups)return;c.groups.forEach(g=>{const pi=g.players.indexOf(oldName);if(pi>=0)g.players[pi]=name;});});currentUser=USERS[name];}persist();a.className='alert alert-ok';a.textContent='✓ Datos actualizados.';}
function changePw(){const o=document.getElementById('pw-old').value,n=document.getElementById('pw-new').value,n2=document.getElementById('pw-new2').value,a=document.getElementById('pw-alert');function al(m,t){a.className='alert alert-'+t;a.textContent=m;}if(o!==currentUser.pass){al('La contraseña actual no es correcta.','err');return;}if(!n||n.length<4){al('La nueva contraseña debe tener al menos 4 caracteres.','err');return;}if(n!==n2){al('Las contraseñas nuevas no coinciden.','err');return;}const key=currentUser.role==='admin'?'admin':currentUser.name;USERS[key].pass=n;currentUser.pass=n;al('✓ Contraseña actualizada.','ok');['pw-old','pw-new','pw-new2'].forEach(id=>document.getElementById(id).value='');}
function roundName(ri,total){const fe=total-1-ri;if(fe===0)return'Final';if(fe===1)return'Semifinales';if(fe===2)return'Cuartos';if(fe===3)return'Octavos';if(fe===4)return'16avos';return'Ronda '+(ri+1);}
function matchBox(m,ti,which,ri,mi){const aw=m.w&&m.w===m.a,bw=m.w&&m.w===m.b;const sc=m.sets?m.sets.map(([a,b])=>`${a}-${b}`).join(' '):'';const canLoad=m.a&&m.b&&!m.w&&(currentUser.role==='admin'||m.a===currentUser.name||m.b===currentUser.name);const a=`<div class="slot ${aw?'winner':''} ${!m.a?'empty-slot':''}"><span class="seed">${m.sid[0]||''}</span><span class="nm">${m.a||'Por definir'}</span></div>`;const b=`<div class="slot ${bw?'winner':''} ${!m.b?'empty-slot':''}"><span class="seed">${m.sid[1]||''}</span><span class="nm">${m.b||'Por definir'}</span></div>`;let f='';if(m.w&&m.a&&m.b)f=`<div class="slot slot-foot"><span class="slot-score">${sc}</span><span class="slot-win">✓ ${m.w}</span></div>`;else if(canLoad)f=`<div class="slot slot-center"><button class="po-load" onclick="poReport(${ti},'${which}',${ri},${mi})"><i class="ti ti-upload"></i> Cargar resultado</button></div>`;else if(m.a&&m.b)f=`<div class="slot slot-center"><span class="lock-note">A jugar</span></div>`;return`<div class="match-wrap"><div class="match-box">${a}${b}${f}</div></div>`;}
function bracketHTML(rounds,ti,which){const total=rounds.length;return `<div class="bracket ${which==='cons'?'bracket-cons':'bracket-main'}">${rounds.map((rd,ri)=>{const rn=roundName(ri,total);const fd=which==='main'?fmtStageDate(rn):'';return `<div class="round"><div class="round-lbl">${rn}${fd?`<div class="round-date">${fd}</div>`:''}</div><div class="round-body">${rd.map((m,mi)=>matchBox(m,ti,which,ri,mi)).join('')}</div></div>`;}).join('')}</div>`;}
function fmtD(iso){if(!iso)return'';const p=iso.split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0].slice(2)}`:iso;}
function fmtStageDate(nm){const sd=playoff.stageDates&&playoff.stageDates[nm];if(!sd||!sd.d1)return'';const f=fmtD(sd.d1);return (sd.mode==='range'&&sd.d2)?f+' – '+fmtD(sd.d2):f;}
function setStageMode(nm,mode){if(!playoff.stageDates)playoff.stageDates={};const sd=playoff.stageDates[nm]||{d1:'',d2:''};sd.mode=mode;playoff.stageDates[nm]=sd;showPlayoffView();}
function setStageD(nm,which,val){if(!playoff.stageDates)playoff.stageDates={};const sd=playoff.stageDates[nm]||{mode:'single',d1:'',d2:''};sd[which]=val;playoff.stageDates[nm]=sd;showPlayoffView();}
function stageDatesCard(tr){if(!playoff.stageDates)playoff.stageDates={};const names=tr.main.map((_,ri)=>roundName(ri,tr.main.length));const rows=names.map(nm=>{const sd=playoff.stageDates[nm]||{mode:'single',d1:'',d2:''};return `<div class="form-row" style="grid-template-columns:1fr 1fr 1fr;align-items:end;margin-bottom:.4rem"><div class="form-group"><label>${nm}</label><select onchange="setStageMode('${esc(nm)}',this.value)"><option value="single" ${sd.mode!=='range'?'selected':''}>Fecha única</option><option value="range" ${sd.mode==='range'?'selected':''}>Semana de juego</option></select></div><div class="form-group"><label>${sd.mode==='range'?'Desde':'Fecha'}</label><input type="date" value="${sd.d1||''}" onchange="setStageD('${esc(nm)}','d1',this.value)"></div><div class="form-group" style="${sd.mode==='range'?'':'visibility:hidden'}"><label>Hasta</label><input type="date" value="${sd.d2||''}" onchange="setStageD('${esc(nm)}','d2',this.value)"></div></div>`;}).join('');return `<div class="card"><div class="section-lbl">Fechas de las etapas</div>${rows}<p class="legend-txt" style="margin-top:0">Para cada ronda elegí "Semana de juego" (rango desde–hasta) o "Fecha única". Aparece debajo del nombre de la ronda en el cuadro.</p></div>`;}
function showPlayoffView(){['grupos','general','cargar','pendientes','admin','perfil'].forEach(v=>{var el=document.getElementById('view-'+v);if(el)el.style.display='none';});const pv=document.getElementById('view-playoff');pv.style.display='block';const isPrev=playoff.preview&&!playoff.started;if(!playoff.started&&!isPrev){pv.innerHTML='<div class="card"><div class="empty">El admin todavía no inició los Play Offs.</div></div>';return;}if(isPrev&&currentUser.role!=='admin'){pv.innerHTML='<div class="card"><div class="empty">Los Play Offs todavía no están disponibles.</div></div>';return;}let html='';if(isPrev){html+=`<div class="card" style="border:2px solid var(--pri)"><div class="po-section-title" style="margin-bottom:.5rem"><i class="ti ti-eye"></i> Previsualización — los Play Offs todavía NO están iniciados</div><p class="legend-txt" style="margin-top:0">Así quedarían los cuadros según la clasificación general. Quitá o agregá jugadores (los que no juegan) y ajustá la cantidad de cuadros. Cuando esté todo listo, confirmá el inicio. Hasta entonces los jugadores no ven nada.</p><button class="btn btn-accent" onclick="confirmPlayoffUI()"><i class="ti ti-player-play"></i> Iniciar Play Offs definitivamente</button></div>`;}if(currentUser.role==='admin'){html+=`<div class="card"><div class="section-lbl">Configuración de Play Offs</div><div class="form-row"><div class="form-group"><label>Cantidad de cuadros</label><select onchange="setPoNum(this.value)">${[1,2,3,4,5,6].map(k=>`<option value="${k}" ${playoff.numTramos===k?'selected':''}>${k} cuadro${k>1?'s':''}</option>`).join('')}</select></div></div><p class="legend-txt" style="margin-top:0">Al cambiar la cantidad, los cuadros se rearman repartiendo la clasificación general en partes iguales.</p></div>`;}
html+=`<div class="po-tramos">`+playoff.tramos.map((tr,i)=>`<button class="po-tab ${playoff.viewT===i?'active':''}" onclick="setViewT(${i})">Cuadro ${tr.label}<br><span class="po-rng">${tr.seeds.length} jug.</span></button>`).join('')+`</div>`;
const ti=playoff.viewT;const tr=playoff.tramos[ti];if(!tr){pv.innerHTML=html+'<div class="card"><div class="empty">Sin cuadro.</div></div>';updateHdr();return;}
if(currentUser.role==='admin'){const inPo={};playoff.tramos.forEach(t=>t.seeds.forEach(n=>inPo[n]=1));const avail=ALLNAMES.filter(n=>!inPo[n]);html+=`<div class="card"><div class="section-lbl">Jugadores del Cuadro ${tr.label} — quitá (✕) o agregá</div><div class="seed-list">${tr.seeds.map(n=>`<span class="seed-chip">${n} <button class="rm" onclick="removeSeedUI(${ti},'${esc(n)}')" aria-label="Quitar"><i class="ti ti-x"></i></button></span>`).join('')}</div><div class="form-row" style="margin-top:.6rem"><div class="form-group"><label>Agregar jugador a este cuadro</label><select id="po-add"><option value="">Elegí…</option>${avail.map(n=>`<option value="${n}">${n}</option>`).join('')}</select></div><div class="form-group" style="align-self:end"><button class="btn btn-primary btn-sm" onclick="addSeedUI(${ti})"><i class="ti ti-plus"></i> Agregar</button></div></div><p class="legend-txt">Si quitás a alguien, no se reemplaza: pasa uno más por <b>bye</b>.</p></div>`;html+=stageDatesCard(tr);}
const finalM=tr.main[tr.main.length-1][0];html+=`<div class="card"><div class="po-section-title"><i class="ti ti-trophy"></i> Cuadro principal ${tr.label}</div>${bracketHTML(tr.main,ti,'main')}${finalM.w?`<div class="champ-card"><div class="lbl">Campeón ${tr.label}</div><div class="who"><i class="ti ti-crown"></i> ${finalM.w}</div></div>`:''}</div>`;
if(tr.cons){const cf=tr.cons[tr.cons.length-1][0];html+=`<div class="card"><div class="po-section-title po-cons-title"><i class="ti ti-shield"></i> Consolación ${tr.label} (perdedores 1ª ronda)</div>${bracketHTML(tr.cons,ti,'cons')}${cf.w?`<div class="champ-card champ-cons"><div class="lbl">Campeón consolación ${tr.label}</div><div class="who">${cf.w}</div></div>`:''}</div>`;}
html+=`<div class="card legend-card"><p class="legend-txt">Cada cuadro toma una franja de la clasificación general (el Cuadro A los mejores, y así). Los jugadores cargan su resultado y el rival confirma (o el admin valida). Perdedores de la 1ª ronda pasan a consolación. El admin agrega/quita jugadores y define cuántos cuadros hay.</p></div>`;
pv.innerHTML=html;updateHdr();}
function setViewT(i){playoff.viewT=i;showPlayoffView();}
function removeSeedUI(t,n){removeSeed(t,n);showPlayoffView();toast(n+' quitado del cuadro (pasa uno por bye).');}
function addSeedUI(t){const v=document.getElementById('po-add').value;if(!v){toast('Elegí un jugador para agregar.');return;}addSeed(t,v);showPlayoffView();toast(v+' agregado al cuadro.');}
function poReport(ti,which,ri,mi){const tr=playoff.tramos[ti];const m=(which==='main'?tr.main:tr.cons)[ri][mi];if(!m.a||!m.b){toast('Ese partido todavía no tiene los dos jugadores.');return;}if(m.locked&&currentUser.role!=='admin'){toast('Resultado ya validado. Solo el admin puede editarlo.');return;}if(currentUser.role==='player'&&m.a!==currentUser.name&&m.b!==currentUser.name){toast('Solo los jugadores de ese partido (o el admin) pueden cargarlo.');return;}poContext={ti,which,ri,mi};openPoForm(m,ti);}
function openPoForm(m,ti){document.getElementById('modal-title').textContent='Cargar resultado · Cuadro '+playoff.tramos[ti].label;document.getElementById('modal-body').innerHTML=`<p class="modal-rep">${m.a} <span class="vs">vs</span> ${m.b}</p><div class="set-row"><label>Set 1</label><input type="number" id="po-s1a" min="0" max="7" class="po-in"><span class="sep">–</span><input type="number" id="po-s1b" min="0" max="7" class="po-in"></div><div class="set-row"><label>Set 2</label><input type="number" id="po-s2a" min="0" max="7" class="po-in"><span class="sep">–</span><input type="number" id="po-s2b" min="0" max="7" class="po-in"></div><div class="set-row" id="po-s3-row" style="display:none"><label>S.Tiebreak</label><input type="number" id="po-s3a" min="0" max="1" class="po-in"><span class="sep">–</span><input type="number" id="po-s3b" min="0" max="1" class="po-in"><span class="set-hint">1-0 o 0-1</span></div><button class="btn btn-sm" onclick="document.getElementById('po-s3-row').style.display='flex'" style="margin-top:4px"><i class="ti ti-plus"></i> Supertiebreak</button><p class="lock-note" id="po-alert" style="margin-top:.5rem"></p>`;document.getElementById('modal-actions').innerHTML=`<button class="btn btn-accent" onclick="submitPo()"><i class="ti ti-send"></i> ${currentUser.role==='admin'?'Guardar y validar':'Enviar (rival confirma)'}</button><button class="btn" onclick="closeM()">Cancelar</button>`;document.getElementById('modal-bg').classList.add('open');}
function submitPo(){const s=[[+document.getElementById('po-s1a').value,+document.getElementById('po-s1b').value],[+document.getElementById('po-s2a').value,+document.getElementById('po-s2b').value]];if(document.getElementById('po-s3-row').style.display!=='none')s.push([+document.getElementById('po-s3a').value,+document.getElementById('po-s3b').value]);const v=validMatch(s);if(!v.ok){const a=document.getElementById('po-alert');a.textContent='✕ '+v.msg;a.classList.add('err-txt');return;}const ti=poContext.ti,which=poContext.which,ri=poContext.ri,mi=poContext.mi;const m=(which==='main'?playoff.tramos[ti].main:playoff.tramos[ti].cons)[ri][mi];let w1=0,w2=0;s.forEach(([a,b])=>{if(a>b)w1++;else w2++;});const winner=w1>w2?m.a:m.b;if(currentUser.role==='admin'){storePo(ti,which,m.a,m.b,s,winner);rebuildTramo(ti);closeM();showPlayoffView();toast('Resultado de Play Off validado.');}else{matches.push({id:matchId++,po:true,ti,which,tLabel:playoff.tramos[ti].label,poNames:[m.a,m.b],sets:s,status:'pending',reporter:currentUser.name,winner,date:'2026'});closeM();renderPend();renderCycleBar();showPlayoffView();toast('Resultado enviado. El rival debe confirmarlo.');}}
function storePo(ti,which,a,b,sets,w){const k=(which==='main'?ti:ti+'c')+'#'+[a,b].sort().join('|');playoff.results[k]={sets,w};}
function applyPoPending(rec){storePo(rec.ti,rec.which,rec.poNames[0],rec.poNames[1],rec.sets,rec.winner);rebuildTramo(rec.ti);}
function refreshAll(){try{if(typeof persist==='function')persist();}catch(e){}if(viewCycle==='po'){showPlayoffView();renderPend();renderCycleBar();return;}if(subView==='grupos')renderGrupos();if(subView==='general')renderGeneral();if(subView==='pendientes')renderPend();if(subView==='admin')renderAdmin();if(subView==='cargar')renderCargarDisputas();renderPend();renderCycleBar();}
function toast(m){let t=document.getElementById('_toast');if(!t){t=document.createElement('div');t.id='_toast';t.className='toast';document.body.appendChild(t);}t.textContent=m;t.style.opacity='1';setTimeout(()=>t.style.opacity='0',3800);}
initLogin();

// ===== Conexión con Supabase (guarda y comparte los datos) =====
// Si no pegás tus claves, la app funciona igual pero en modo local (sin guardar).
let _sb=null,_lastSaved=null,_saving=false;
function _serialize(){return JSON.stringify({cycles,matches,matchId,activeN,playoff,DESTINO,FECHAS,ALLNAMES,users:USERS});}
function _hydrate(d){try{
  if(d.cycles)cycles=d.cycles;
  if(Array.isArray(d.matches))matches=d.matches;
  if(typeof d.matchId==='number')matchId=d.matchId;
  if(typeof d.activeN==='number')activeN=d.activeN;
  if(d.playoff)playoff=d.playoff;
  if(d.DESTINO)DESTINO=d.DESTINO;
  if(d.FECHAS)FECHAS=d.FECHAS;
  if(Array.isArray(d.ALLNAMES))ALLNAMES=d.ALLNAMES;
  if(d.users){Object.keys(USERS).forEach(k=>delete USERS[k]);Object.assign(USERS,d.users);}
}catch(e){console.warn('hydrate',e);}}
function initSupabase(){try{if(typeof window!=='undefined'&&window.supabase&&typeof SUPA_URL==='string'&&SUPA_URL&&SUPA_URL.indexOf('PEGA_')<0){_sb=window.supabase.createClient(SUPA_URL,SUPA_KEY);}}catch(e){_sb=null;}}
async function loadState(){if(!_sb)return;const r=await _sb.from('liga_state').select('data').eq('id',1).maybeSingle();if(r.error)throw r.error;if(r.data&&r.data.data){_hydrate(typeof r.data.data==='string'?JSON.parse(r.data.data):r.data.data);_lastSaved=_serialize();}else{await persist(true);}}
async function persist(force){if(!_sb||_saving)return;const json=_serialize();if(!force&&json===_lastSaved)return;_saving=true;try{const r=await _sb.from('liga_state').upsert({id:1,data:json});if(!r.error)_lastSaved=json;else console.warn('persist',r.error);}catch(e){console.warn('persist',e);}_saving=false;}
if(typeof setInterval!=='undefined')setInterval(function(){persist();},3000);
if(typeof window!=='undefined'&&window.addEventListener)window.addEventListener('beforeunload',function(){try{persist(true);}catch(e){}});
initSupabase();
(async function(){try{await loadState();}catch(e){console.warn('Supabase load',e);}initLogin();})();
